DROP TABLE IF EXISTS `ai_call_logs`;
CREATE TABLE `ai_call_logs`  (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `app_key_id` int(11) NULL DEFAULT NULL,
  `provider_id` int(11) NULL DEFAULT NULL,
  `model` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `stream` tinyint(1) NOT NULL DEFAULT 0,
  `prompt_tokens` int(11) NULL DEFAULT NULL,
  `completion_tokens` int(11) NULL DEFAULT NULL,
  `total_tokens` int(11) NULL DEFAULT NULL,
  `duration_ms` int(11) NULL DEFAULT NULL,
  `status_code` int(11) NULL DEFAULT NULL,
  `success` tinyint(1) NOT NULL DEFAULT 1,
  `error_msg` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_acl_created_at`(`created_at`) USING BTREE,
  INDEX `idx_acl_app_key`(`app_key_id`) USING BTREE,
  INDEX `idx_acl_provider`(`provider_id`) USING BTREE,
  INDEX `idx_acl_model`(`model`) USING BTREE,
  CONSTRAINT `fk_acl_appkey` FOREIGN KEY (`app_key_id`) REFERENCES `app_keys` (`id`) ON DELETE SET NULL ON UPDATE RESTRICT,
  CONSTRAINT `fk_acl_provider` FOREIGN KEY (`provider_id`) REFERENCES `ai_providers` (`id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1441 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

